        })}
      </Text>
    );
  }

  return (
    <View style={{ gap: 10 }}>
      <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '800' }}>{copy({ de: 'Letzte Rivalen', en: 'Recent rivals', pl: 'Ostatni rywale' })}</Text>
